/**
 * useEvents Hook
 *
 * 用于管理组件事件和动作的 React Hook
 *
 * @example
 * ```tsx
 * import { usePageVarValue } from '@airiot/client'
 *
 * function MyComponent() {
 *   const events = useEvents({
 *     click: [
 *       { type: 'changeVar', params: { var: { path: 'a' }, varValue: 'haha' } },
 *       { type: 'pageJump', params: { url: '/home' } }
 *     ],
 *     doubleClick: []
 *   })
 *
 *   // 使用 @airiot/client 的 usePageVarValue 读取和验证变量
 *   const varA = usePageVarValue('a')
 *
 *   return (
 *     <div {...events}>
 *       <p>变量 a: {JSON.stringify(varA)}</p>
 *       <Button onClick={events.click}>Click me</Button>
 *       <Card onDoubleClick={events.doubleClick}>Double click me</Card>
 *     </div>
 *   )
 * }
 * ```
 */

'use client'

import { useState, useMemo, useCallback, useRef } from 'react'
import { useSetPageVar } from '@airiot/client'
import type {
  EventConfig,
  EventType,
  EventsReturn,
  Action,
  EventContext,
} from './events.types'
import { executeActions } from './event-execution'
import { eventTypeToReactEvent } from './event-execution'

/**
 * useEvents Hook
 *
 * @param config - 事件配置对象，键为事件类型，值为动作数组
 * @returns 事件处理器对象
 */
export function useEvents(config: EventConfig = {}): EventsReturn {

  const setPageVar = useSetPageVar()

  // 状态管理
  const [loading, setLoading] = useState(false)
  const [_error, setError] = useState<string | null>(null)

  // 使用 ref 避免在循环中依赖 loading
  const loadingRef = useRef(loading)
  loadingRef.current = loading

  // 创建事件处理器
  const handlers = useMemo(() => {
    const result: Record<EventType, (e?: React.SyntheticEvent) => Promise<void>> = {} as any

    for (const [eventType, actions] of Object.entries(config)) {
      if (actions && actions.length > 0) {
        result[eventType as EventType] = async (e?: React.SyntheticEvent) => {
          // 如果正在执行，则忽略
          if (loadingRef.current) {
            return Promise.resolve()
          }

          e?.preventDefault()

          setLoading(true)
          setError(null)

          try {
            const context: EventContext = {
              eventType: eventType as EventType,
              eventParams: e,
              eventFunctions: {
                setPageVar,
              },
            }

            const results = await executeActions(actions, context)

            // 检查是否有失败的执行
            const failedResult = results.find((r) => !r.success)
            if (failedResult) {
              setError(failedResult.error || '动作执行失败')
            }
          } catch (err) {
            const errorMessage = err instanceof Error ? err.message : '未知错误'
            setError(errorMessage)
          } finally {
            setLoading(false)
          }
        }
      }
    }

    return result
  }, [config, setPageVar])

  // 返回事件处理器和配置
  return {
    ...handlers,
    config,
  } as EventsReturn
}

/**
 * useEvent Hook - 单个事件的快捷方式
 *
 * @param eventType - 事件类型
 * @param actions - 动作数组
 * @returns 事件处理器函数和状态
 */
export function useEvent(
  eventType: EventType,
  actions: Action[] = []
) {
  const [loading, setLoading] = useState(false)
  const [error, setError] = useState<string | null>(null)

  // 自动创建页面变量设置函数
  const setPageVar = useSetPageVar()

  const loadingRef = useRef(loading)
  loadingRef.current = loading

  const handler = useCallback(async (e?: React.SyntheticEvent) => {
    if (!actions || actions.length === 0 || loadingRef.current) {
      return Promise.resolve()
    }

    e?.preventDefault()

    setLoading(true)
    setError(null)

    try {
      const context: EventContext = {
        eventType,
        eventParams: e,
        eventFunctions: {
          setPageVar,
        },
      }

      const results = await executeActions(actions, context)

      const failedResult = results.find((r) => !r.success)
      if (failedResult) {
        setError(failedResult.error || '动作执行失败')
      }
    } catch (err) {
      const errorMessage = err instanceof Error ? err.message : '未知错误'
      setError(errorMessage)
    } finally {
      setLoading(false)
    }
  }, [eventType, actions, setPageVar])

  return { handler, loading, error }
}

/**
 * useEventWithSpread Hook - 返回可展开的事件处理器对象
 *
 * @example
 * ```tsx
 * const events = useEventsWithSpread({
 *   click: [{ type: 'changeVar', params: { ... } }],
 *   doubleClick: [{ type: 'pageJump', params: { ... } }]
 * })
 *
 * // 可以展开到组件上
 * <div {...events}>
 *   <Button>Click me</Button>
 * </div>
 *
 * // 也可以单独使用
 * <Button onClick={events.onClick}>Click me</Button>
 * ```
 */
export function useEventsWithSpread(config: EventConfig = {}) {
  const handlers = useEvents(config)

  // 转换为 React 事件格式（onClick, onDoubleClick 等）
  const reactHandlers = useMemo(() => {
    const result: Record<string, (e?: React.SyntheticEvent) => Promise<void>> = {}

    for (const [eventType, handler] of Object.entries(handlers)) {
      // 跳过 config 属性
      if (eventType === 'config') {
        continue
      }
      const reactEventName = eventTypeToReactEvent[eventType as EventType]
      if (reactEventName && typeof handler === 'function') {
        result[reactEventName] = handler
      }
    }

    return result
  }, [handlers])

  return reactHandlers
}

// ============== 导出所有相关类型和函数 ==============

export * from './events.types'
export * from './event-execution'
export * from './action-handlers'

/**
 * 事件和动作类型定义
 */

/** 事件类型 */
export type EventType =
  | 'click' // 单击
  | 'doubleClick' // 双击
  | 'mouseEnter' // 移入
  | 'mouseLeave' // 移出
  | 'change' // 值变化
  | 'submit' // 表单提交
  | 'focus' // 聚焦
  | 'blur' // 失焦
  | 'input' // 输入

/** 动作类型 */
export type ActionType =
  | 'pageJump' // 页面跳转
  | 'changeVar' // 修改变量
  | 'changeTableData' // 修改表数据
  | 'changeDict' // 修改数据字典
  | 'changeDataPoint' // 修改数据点配置
  | 'changeSystemSetting' // 修改系统设置
  | 'changeUser' // 修改用户
  | 'callFlow' // 调用流程
  | 'executeCommand' // 执行指令
  | 'sendRequest' // 发送请求

/** 值类型 - 变量值或组件值 */
export type ValueType = 'varValue' | 'comValue'

/** 执行结果消息配置 */
export interface ResultMessage {
  /** 成功提示 */
  successMess?: boolean
  /** 成功显示时常（秒） */
  successTime?: number
  /** 成功显示内容 */
  successContent?: string
  /** 失败提示 */
  errorMess?: boolean
  /** 失败显示时常（秒） */
  errorTime?: number
  /** 失败显示内容 */
  errorContent?: string
}

/** 打开方式 */
export type OpenWay = '_blank' | '_self' | '_parent' | '_top'

/** 权限类型 */
export type PermissionType = 'users' | 'roles'

/** 页面跳转动作参数 */
export interface PageJumpParams {
  url: string
  openWay?: OpenWay
  showMessage?: boolean
  permission?: PermissionType
  users?: string[]
  roles?: string[]
}

/** 修改变量动作参数 */
export interface ChangeVarParams extends ResultMessage {
  var: Record<string, any>
  varValue?: Record<string, any>
}

/** 修改表数据动作参数 */
export interface ChangeTableDataParams extends ResultMessage {
  table: Record<string, any>
  data: Record<string, any>
  /** 触发时修改（弹出表单） */
  showForm?: boolean
  fields?: string[]
  nodeProp?: Array<{
    key: string
    value: string
  }>
}

/** 修改数据字典动作参数 */
export interface ChangeDictParams extends ResultMessage {
  systemVar: Record<string, any>
  value?: Record<string, any>
}

/** 数据点属性 */
export interface DataPointProperty {
  /** 资产数据点 */
  recordDataPoint?: {
    tableId: string
    tableDataId: string
    tagId: string
  }
  /** 模型数据点 */
  tableDataPoint?: {
    tableId: string
    tagId: string
  }
  /** 要更新的属性键 */
  key: string
  /** 要设置的值 */
  value?: any
}

/** 修改数据点配置动作参数 */
export interface ChangeDataPointParams extends ResultMessage {
  /** 触发时修改（弹出表单） */
  showForm?: boolean
  /** 数据点配置数组 */
  dataPointMulti: DataPointProperty[]
}

/** 字段和值 */
export interface FieldValuePair {
  key: string
  value: string
}

/** 修改系统设置动作参数 */
export interface ChangeSystemSettingParams extends ResultMessage {
  /** 触发时修改（弹出表单） */
  showForm?: boolean
  fields?: string[]
  nodeProp?: FieldValuePair[]
}

/** 修改用户动作参数 */
export interface ChangeUserParams extends ResultMessage {
  /** 触发时修改（弹出表单） */
  showForm?: boolean
  fields?: string[]
  nodeProp?: FieldValuePair[]
}

/** 调用流程动作参数 */
export interface CallFlowParams extends ResultMessage {
  flow: Record<string, any>
  /** 触发时修改（弹出表单） */
  showForm?: boolean
  params?: Record<string, any>
}

/** 动作基础接口 */
export interface Action {
  /** 动作类型 */
  type: ActionType
  /** 动作参数 */
  params: any
  /** 是否需要二次确认 */
  confirm?: {
    title?: string
    message?: string
    confirmText?: string
    cancelText?: string
  }
  /** 延迟执行（毫秒） */
  delay?: number
}

/** 事件配置 */
export interface EventConfig {
  [eventType: string]: Action[]
}

/** 事件函数集合 */
export interface EventFunctions {
  /** 设置页面变量 */
  setPageVar?: (path: string, value: any) => void
}

/** 事件执行上下文 */
export interface EventContext {
  /** 事件源组件 */
  component?: React.ComponentType<any>
  /** 当前事件类型 */
  eventType: EventType
  /** 事件触发参数（如事件对象） */
  eventParams?: any
  /** 前一个动作的执行结果 */
  prevResult?: any
  /** 事件函数集合 */
  eventFunctions?: EventFunctions
}

/** 动作执行结果 */
export interface ActionResult {
  /** 是否成功 */
  success: boolean
  /** 返回数据 */
  data?: any
  /** 错误信息 */
  error?: string
}

/** 动作处理器 */
export type ActionHandler = (
  params: any,
  context: EventContext
) => Promise<ActionResult> | ActionResult

/** 事件处理器返回值 */
export interface EventHandlerReturn {
  /** 事件处理函数 */
  handler: (e?: React.SyntheticEvent) => void | Promise<void>
  /** 是否正在执行 */
  loading: boolean
  /** 执行错误 */
  error: string | null
}

/** 事件配置对象 */
export interface EventsReturn extends Partial<Record<EventType, (e?: React.SyntheticEvent) => void | Promise<void>>> {
  /** 各事件的处理器 */
  [key: string]: ((e?: React.SyntheticEvent) => void | Promise<void>) | EventConfig | undefined
  /** 事件配置原始数据 */
  config: EventConfig
}

/**
 * 事件执行工具函数
 */

import type {
  Action,
  ActionResult,
  EventConfig,
  EventContext,
  EventFunctions,
  EventType,
} from './events.types'
import { getActionHandler } from './action-handlers'
import {
  showConfirmDialog as baseShowConfirmDialog,
  showFormDialog as baseShowFormDialog,
} from './dialog-atom'

/**
 * 解析事件类型到 React 事件名称的映射
 */
export const eventTypeToReactEvent: Record<EventType, string> = {
  click: 'onClick',
  doubleClick: 'onDoubleClick',
  mouseEnter: 'onMouseEnter',
  mouseLeave: 'onMouseLeave',
  change: 'onChange',
  submit: 'onSubmit',
  focus: 'onFocus',
  blur: 'onBlur',
  input: 'onInput',
}

/**
 * 解析 React 事件名称到事件类型的映射
 */
export const reactEventToEventType: Record<string, EventType> = {
  onClick: 'click',
  onDoubleClick: 'doubleClick',
  onMouseEnter: 'mouseEnter',
  onMouseLeave: 'mouseLeave',
  onChange: 'change',
  onSubmit: 'submit',
  onFocus: 'focus',
  onBlur: 'blur',
  onInput: 'input',
}

/**
 * 显示二次确认对话框
 */
export function showConfirmDialog(
  confirmConfig?: {
    title?: string
    message?: string
    confirmText?: string
    cancelText?: string
  }
): Promise<boolean> {

  return baseShowConfirmDialog(confirmConfig)
}

/**
 * 显示表单对话框
 */
export function showFormDialog(
  fields: any[],
  initialValues?: Record<string, any>,
  title?: string,
  description?: string
): Promise<Record<string, any> | null> {
  return baseShowFormDialog(fields, initialValues, title, description)
}

/**
 * 执行单个动作
 */
export async function executeAction(
  action: Action,
  context: EventContext
): Promise<ActionResult> {

  try {
    // 检查是否需要二次确认
    if (action.confirm) {

      const confirmed = await showConfirmDialog(action.confirm)

      if (!confirmed) {
        return { success: false, error: '用户取消操作' }
      }
    }

    // 检查是否需要延迟执行
    if (action.delay && action.delay > 0) {
      await new Promise((resolve) => setTimeout(resolve, action.delay))
    }

    // 获取动作处理器并执行
    const handler = getActionHandler(action.type)
    const result = await handler(action.params, context)

    return result
  } catch (error) {
    return {
      success: false,
      error: error instanceof Error ? error.message : '执行动作失败',
    }
  }
}

/**
 * 获取动作需要显示的表单字段
 */
function getFormFieldsForAction(
  actionType: string,
  params: any
): {
  fields: any[]
  initialValues?: Record<string, any>
  title?: string
  description?: string
} {
  const result: {
    fields: any[]
    initialValues?: Record<string, any>
    title?: string
    description?: string
  } = {
    fields: [],
    title: '填写信息',
    description: '请填写以下信息',
  }

  switch (actionType) {
    case 'changeTableData':
      result.title = '修改表数据'
      result.description = '请输入要修改的数据'
      if (params.nodeProp) {
        result.fields = params.nodeProp.map((item: any) => ({
          name: item.key,
          label: item.key,
          type: 'text',
          defaultValue: item.value,
          required: true,
        }))
      }
      break

    case 'changeDataPoint':
      result.title = '修改数据点配置'
      result.description = '请输入数据点属性'
      if (params.dataPointMulti) {
        result.fields = params.dataPointMulti.map((item: any) => ({
          name: `dp_${item.dataPoint?.id || 'unknown'}_${item.key}`,
          label: `${item.dataPoint?.name || '数据点'} - ${item.key}`,
          type: 'text',
          defaultValue: item.value,
          required: true,
        }))
      }
      break

    case 'changeSystemSetting':
      result.title = '修改系统设置'
      result.description = '请输入系统设置信息'
      if (params.nodeProp) {
        result.fields = params.nodeProp.map((item: any) => ({
          name: item.key,
          label: item.key,
          type: 'text',
          defaultValue: item.value,
          required: true,
        }))
      }
      break

    case 'changeUser':
      result.title = '修改用户信息'
      result.description = '请输入用户信息'
      if (params.nodeProp) {
        result.fields = params.nodeProp.map((item: any) => ({
          name: item.key,
          label: item.key,
          type: 'text',
          defaultValue: item.value,
          required: true,
        }))
      }
      break

    case 'callFlow':
      result.title = '调用流程'
      result.description = '请输入流程参数'
      if (params.params) {
        result.initialValues = params.params
        result.fields = Object.keys(params.params).map((key) => ({
          name: key,
          label: key,
          type: 'text',
          defaultValue: params.params[key],
        }))
      }
      break

    default:
      break
  }

  return result
}

/**
 * 执行事件的所有动作（按顺序）
 */
export async function executeActions(
  actions: Action[],
  context: EventContext
): Promise<ActionResult[]> {
  const results: ActionResult[] = []
  let prevResult: any = undefined

  for (let i = 0; i < actions.length; i++) {
    const action = actions[i]
    const actionContext = {
      ...context,
      prevResult,
    }

    const result = await executeAction(action, actionContext)
    results.push(result)

    // 保存当前结果供下一个动作使用
    if (result.success) {
      prevResult = result.data
    } else {
      // 如果动作执行失败，可以选择停止或继续
      // 这里选择停止执行后续动作
      break
    }
  }

  return results
}

/**
 * 创建事件处理器函数
 */
export function createEventHandler(
  eventType: EventType,
  actions: Action[],
  onLoadingChange?: (loading: boolean) => void,
  onError?: (error: string) => void,
  eventFunctions?: EventFunctions
) {
  return async (e?: React.SyntheticEvent) => {
    if (!actions || actions.length === 0) {
      return
    }

    // 阻止默认行为（如表单提交）
    e?.preventDefault()

    onLoadingChange?.(true)

    try {
      const context: EventContext = {
        eventType,
        eventParams: e,
        eventFunctions,
      }

      const results = await executeActions(actions, context)

      // 检查是否有失败的执行
      const hasFailure = results.some((r) => !r.success)
      if (hasFailure) {
        const lastError = results.reverse().find((r) => r.error)?.error
        onError?.(lastError || '事件执行失败')
      }
    } catch (error) {
      const errorMessage =
        error instanceof Error ? error.message : '未知错误'
      onError?.(errorMessage)
    } finally {
      onLoadingChange?.(false)
    }
  }
}

/**
 * 解析事件配置，生成事件处理器映射
 */
export function parseEventConfig(
  config: EventConfig,
  eventFunctions?: EventFunctions
): Record<EventType, (e?: React.SyntheticEvent) => Promise<void>> {
  const handlers: Record<
    EventType,
    (e?: React.SyntheticEvent) => Promise<void>
  > = {} as any

  for (const [eventType, actions] of Object.entries(config)) {
    if (actions && actions.length > 0) {
      handlers[eventType as EventType] = createEventHandler(
        eventType as EventType,
        actions,
        undefined,
        undefined,
        eventFunctions
      )
    }
  }

  return handlers
}
